msg.topic = `CREATE TABLE IF NOT EXISTS \`indicadores_opc\` (\`id\` INT NOT NULL AUTO_INCREMENT,\`timestamp\` DATETIME NOT NULL,\`velocidad_molino1\` FLOAT DEFAULT NULL,\`velocidad_molino6\` FLOAT DEFAULT NULL,\`balanza_cinta\` FLOAT DEFAULT NULL,\`agua_imbibicion\` FLOAT DEFAULT NULL,\`presion_molino6_este\` FLOAT DEFAULT NULL,\`presion_molino6_oeste\` FLOAT DEFAULT NULL,\`caudal_jugo_clarif\` FLOAT DEFAULT NULL,\`nivel_melado_tratado\` FLOAT DEFAULT NULL,\`nivel_melado\` FLOAT DEFAULT NULL,\`nivel_decantador1\` FLOAT DEFAULT NULL,\`nivel_decantador2\` FLOAT DEFAULT NULL,\`nivel_decantador3\` FLOAT DEFAULT NULL,\`descarga_tachos_1ra\` FLOAT DEFAULT NULL,\`descarga_tachos_2da\` FLOAT DEFAULT NULL,\`descarga_tachos_3ra\` FLOAT DEFAULT NULL,\`contador_bolsas_dia\` FLOAT DEFAULT NULL,\`silo_a\` FLOAT DEFAULT NULL,\`silo_b\` FLOAT DEFAULT NULL,\`silo_c\` FLOAT DEFAULT NULL,\`silo_e\` FLOAT DEFAULT NULL,\`presion_vapor_directo\` FLOAT DEFAULT NULL,\`presion_agua_alim\` FLOAT DEFAULT NULL,\`presion_aire\` FLOAT DEFAULT NULL,\`caudal_vapor_cald1\` FLOAT DEFAULT NULL,\`caudal_vapor_cald2\` FLOAT DEFAULT NULL,\`caudal_vapor_cald3\` FLOAT DEFAULT NULL,\`caudal_vapor_cald6\` FLOAT DEFAULT NULL,\`vapor_total\` FLOAT DEFAULT NULL,\`caudal_gas_cald2\` FLOAT DEFAULT NULL,\`caudal_gas_cald6\` FLOAT DEFAULT NULL,\`potencia_activa_siemens\` FLOAT DEFAULT NULL,\`potencia_reactiva_siemens\` FLOAT DEFAULT NULL,\`frecuencia_siemens\` FLOAT DEFAULT NULL,\`intensidad_siemens\` FLOAT DEFAULT NULL,\`potencia_activa_aeg\` FLOAT DEFAULT NULL,\`potencia_reactiva_aeg\` FLOAT DEFAULT NULL,\`frecuencia_aeg\` FLOAT DEFAULT NULL,\`intensidad_aeg\` FLOAT DEFAULT NULL,\`potencia_total\` FLOAT DEFAULT NULL,\`cv_trapiche\` FLOAT DEFAULT NULL,\`cv_usina_alta\` FLOAT DEFAULT NULL,\`cv_destileria\` FLOAT DEFAULT NULL,\`cv_aux_total\` FLOAT DEFAULT NULL,\`cv_preparacion_cania\` FLOAT DEFAULT NULL,\`caudal_vino\` FLOAT DEFAULT NULL,\`caudal_alcohol\` FLOAT DEFAULT NULL,\`caudal_jugo_dilutor\` FLOAT DEFAULT NULL,\`caudal_melaza_dilutor\` FLOAT DEFAULT NULL,\`temp_calentador\` FLOAT DEFAULT NULL,\`presion_vg1\` FLOAT DEFAULT NULL,\`nivel_agua_foza\` FLOAT DEFAULT NULL,\`caudal_vino_160\` FLOAT DEFAULT NULL,\`presion_k2\` FLOAT DEFAULT NULL,\`potencia_activa_edet\` FLOAT DEFAULT NULL,\`intensidad_edet\` FLOAT DEFAULT NULL,PRIMARY KEY (\`id\`),UNIQUE KEY \`uk_timestamp\` (\`timestamp\`),INDEX \`idx_ts\` (\`timestamp\`)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4`;
msg.payload = [];
return msg;

const now = new Date();
now.setSeconds(0, 0);
const ts = now.toISOString().replace('T', ' ').substring(0, 19);

function g(k) {
    const v = flow.get(k);
    return (v === undefined || v === null || isNaN(parseFloat(v))) ? null : parseFloat(v);
}
function sql(k) { const v = g(k); return v === null ? 'NULL' : v; }

const vt = (g('caudal_vapor_cald1') || 0) + (g('caudal_vapor_cald2') || 0) +
           (g('caudal_vapor_cald3') || 0) + (g('caudal_vapor_cald6') || 0);
const pt = (g('potencia_activa_siemens') || 0) + (g('potencia_activa_aeg') || 0) + (g('potencia_activa_tgm') || 0);

const cols = [
    'velocidad_molino1','velocidad_molino6','balanza_cinta','agua_imbibicion',
    'presion_molino6_este','presion_molino6_oeste','caudal_jugo_clarif','nivel_melado_tratado',
    'nivel_melado','nivel_decantador1','nivel_decantador2','nivel_decantador3',
    'descarga_tachos_1ra','descarga_tachos_2da','descarga_tachos_3ra','contador_bolsas_dia',
    'silo_a','silo_b','silo_c','silo_e',
    'presion_vapor_directo','presion_agua_alim','presion_aire',
    'caudal_vapor_cald1','caudal_vapor_cald2','caudal_vapor_cald3','caudal_vapor_cald6',
    'caudal_gas_cald2','caudal_gas_cald6',
    'potencia_activa_siemens','potencia_reactiva_siemens','frecuencia_siemens','intensidad_siemens',
    'potencia_activa_aeg','potencia_reactiva_aeg','frecuencia_aeg','intensidad_aeg',
    'cv_trapiche','cv_usina_alta','cv_destileria','cv_aux_total','cv_preparacion_cania',
    'potencia_activa_tgm','intensidad_tgm',
    'caudal_vino',
    'nivel_jugo_pesado','nivel_jugo_clarificado','temp_agua_alim','presion_vapor_escape',
    'caudal_agua_dilutor',
    'temp_calentador','presion_vg1','nivel_agua_foza',
    'caudal_vino_160','presion_k2','potencia_activa_edet','intensidad_edet'
];

const vals = cols.map(c => sql(c)).join(',');
const colsQ = cols.map(c => '`' + c + '`').join(',');
const upd = cols.map(c => '`' + c + '`=VALUES(`' + c + '`)').join(',');

msg.topic = 'INSERT INTO `indicadores_opc` (`timestamp`,`vapor_total`,`potencia_total`,' + colsQ +
    ',`caudal_alcohol`,`caudal_jugo_dilutor`,`caudal_melaza_dilutor`) VALUES (' +
    "'" + ts + "'," + vt + ',' + pt + ',' + vals + ',' + sql('caudal_alcohol') + ',' + sql('caudal_jugo_dilutor') + ',' + sql('caudal_melaza_dilutor') + ')' +
    ' ON DUPLICATE KEY UPDATE `vapor_total`=VALUES(`vapor_total`),`potencia_total`=VALUES(`potencia_total`),' + upd +
    ',`caudal_alcohol`=VALUES(`caudal_alcohol`),`caudal_jugo_dilutor`=NULL,`caudal_melaza_dilutor`=NULL';
msg.payload = [];
return msg;

const newCols = [
    'nivel_jugo_pesado',
    'nivel_jugo_clarificado',
    'temp_agua_alim',
    'presion_vapor_escape',
    'caudal_agua_dilutor',
    'temp_calentador',
    'presion_vg1',
    'nivel_agua_foza',
    'caudal_vino_160',
    'presion_k2',
    'potencia_activa_edet',
    'intensidad_edet'
];
const msgs = newCols.map(c => ({
    topic: 'ALTER TABLE `indicadores_opc` ADD COLUMN IF NOT EXISTS `' + c + '` FLOAT DEFAULT NULL',
    payload: []
}));
return [msgs];
